class Solution:
    def kthSmallest(self, root, k: int) -> int:
        stack, cur = [], root
        while cur or stack:          # 中序遍历(BST 中序是升序)
            while cur:
                stack.append(cur)
                cur = cur.left
            cur = stack.pop()
            k -= 1                   # 每访问一个,k 减 1
            if k == 0:               # 减到 0 -> 当前就是第 k 小
                return cur.val
            cur = cur.right
        return -1
